          title: true,
          description: true,
          currency: true,
          length: true,
          requiresConfirmation: true,
          price: true,
        },
      },
    },
  });

  // This should never happen but it's just typescript safe
  if (!foundBooking) {
    throw new Error("Internal Error.");
  }

  // Don't leak any sensitive data
  return foundBooking;
};
